using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
int n, m, a[50005], treex[50005], treen[50005], l, r;
void _add(int x, int k)
{
	while (x <= n)
	{
		treex[x] = max(treex[x], k);
		treen[x] = min(treen[x], k);
		x += lowbit(x);
	}
}
int _findmax(int x, int y)
{
	if (y > x)
	{
		if (y - lowbit(y) > x)return max(treex[y], _findmax(x, y - lowbit(y)));
		else return max(a[y], _findmax(x, y - 1));
	}
	return a[x];
}
int _findmin(int x, int y)
{
	if (y > x)
	{
		if (y - lowbit(y) > x)return min(treen[y], _findmin(x, y - lowbit(y)));
		else return min(a[y], _findmin(x, y - 1));
	}
	return a[x];
}

signed main(void)
{
	memset(treen, 0x3f3f3f3f, sizeof(treen));
	cin >> n >> m;
	for (int i = 1; i <= n; i++)
	{
		cin >> a[i];
		_add(i, a[i]);
	}
	for (int i = 1; i <= m; i++)
	{
		cin >> l >> r;
		cout << _findmax(l, r) - _findmin(l, r) << "\n";
	}
	return false;
}
